import * as React from 'react';
import { IUtils } from '@date-io/core/IUtils';
import { MuiPickersAdapterContext } from '../../LocalizationProvider';

export type MuiPickersAdapter<TDate = unknown> = IUtils<TDate>;

// TODO uncomment when syntax will be allowed by next babel
function checkUtils(utils: MuiPickersAdapter | null) /* :asserts utils is MuiPickersAdapter */ {
  if (!utils) {
    throw new Error(
      'Can not find utils in context. It looks like you forgot to wrap your component in LocalizationProvider, or pass dateAdapter prop directly.'
    );
  }
}

export function useUtils<T = unknown>() {
  const utils = React.useContext(MuiPickersAdapterContext);
  checkUtils(utils);

  return utils as MuiPickersAdapter<T>;
}

export function useNow<TDate = unknown>() {
  const utils = useUtils<TDate>();
  const now = React.useRef(utils.date());

  return now.current!;
}
import * as React from 'react';
import getThemeProps from '@material-ui/styles/getThemeProps';
import { useTheme } from '@material-ui/core/styles';

export function useDefaultProps<T>(props: T, { name }: { name: string }) {
  const theme = useTheme();

  return getThemeProps<any, T, string>({
    props,
    theme,
    name,
  });
}

export function withDefaultProps<T>(
  componentConfig: { name: string },
  Component: React.ComponentType<T>
): React.FC<T> {
  const componentName = componentConfig.name.replace('Mui', '');

  const WithDefaultProps = (props: T) => {
    Component.displayName = componentName;
    const propsWithDefault = useDefaultProps(props, componentConfig);

    return <Component {...propsWithDefault} />;
  };

  WithDefaultProps.displayName = `WithDefaultProps(${componentName})`;
  return WithDefaultProps;
}
export const DIALOG_WIDTH = 320;

export const DIALOG_WIDTH_WIDER = 325;

export const VIEW_HEIGHT = 358;

export const DAY_SIZE = 36;

export const DAY_MARGIN = 2;

export const IS_TOUCH_DEVICE_MEDIA = '@media (pointer: fine)';
